import{_ as e,o as s,c as t,a4 as o}from"./chunks/framework.CDpUjPX_.js";const h=JSON.parse('{"title":"Pipeline de Busca Unificado","description":"","frontmatter":{},"headers":[],"relativePath":"motores/pipeline-busca-unificado.md","filePath":"motores/pipeline-busca-unificado.md"}'),i={name:"motores/pipeline-busca-unificado.md"};function n(d,a,l,r,c,p){return s(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="pipeline-de-busca-unificado" tabindex="-1">Pipeline de Busca Unificado <a class="header-anchor" href="#pipeline-de-busca-unificado" aria-label="Permalink to &quot;Pipeline de Busca Unificado&quot;">​</a></h1><h2 id="visao-geral" tabindex="-1">Visao Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visao Geral&quot;">​</a></h2><p>O Lens de busca por imagem do Kubex executa um pipeline multi-fonte que combina busca visual, banco de pirataria e reconhecimento facial em uma unica operacao.</p><h2 id="fontes-de-dados" tabindex="-1">Fontes de Dados <a class="header-anchor" href="#fontes-de-dados" aria-label="Permalink to &quot;Fontes de Dados&quot;">​</a></h2><h3 id="_1-busca-visual-serpapi" tabindex="-1">1. Busca Visual (SerpAPI) <a class="header-anchor" href="#_1-busca-visual-serpapi" aria-label="Permalink to &quot;1. Busca Visual (SerpAPI)&quot;">​</a></h3><ul><li><strong>Google Lens</strong>: busca reversa de imagem global</li><li><strong>Yandex Images</strong>: cobertura Russia/Leste Europeu</li><li><strong>Baidu Images</strong>: cobertura China/Asia</li><li><strong>Google Images Direct</strong>: fallback se &lt; 5 resultados</li></ul><h3 id="_2-enriquecimento-phash" tabindex="-1">2. Enriquecimento pHash <a class="header-anchor" href="#_2-enriquecimento-phash" aria-label="Permalink to &quot;2. Enriquecimento pHash&quot;">​</a></h3><ul><li>Download de thumbnails dos resultados</li><li>Comparacao perceptual hash (pHash 64-bit)</li><li>Score blend: 70% pHash + 30% posicional (quando pHash 0.65-0.90)</li></ul><h3 id="_3-banco-de-pirataria-pib" tabindex="-1">3. Banco de Pirataria (PIB) <a class="header-anchor" href="#_3-banco-de-pirataria-pib" aria-label="Permalink to &quot;3. Banco de Pirataria (PIB)&quot;">​</a></h3><ul><li>Consulta dominios dos resultados contra <code>PiracyIntelligence</code></li><li>Enriquece resultados com contagem de registros (CPF, CNPJ, PIX, crypto)</li><li>Boost de +0.05 no score para dominios com historico de pirataria</li></ul><h3 id="_4-reconhecimento-facial-kubexfaceindex" tabindex="-1">4. Reconhecimento Facial (KubexFaceIndex) <a class="header-anchor" href="#_4-reconhecimento-facial-kubexfaceindex" aria-label="Permalink to &quot;4. Reconhecimento Facial (KubexFaceIndex)&quot;">​</a></h3><ul><li>Detecta rostos na imagem uploaded via InsightFace (AntelopeV2)</li><li>Se rosto detectado: busca no Milvus (65+ sites indexados)</li><li>Retorna matches faciais mesmo em fotos diferentes (angulo, roupa, iluminacao)</li><li>Resultados com source=&quot;face_match&quot; e score de similaridade coseno</li><li><strong>LGPD</strong>: imagem descartada apos extracao do embedding</li></ul><h2 id="fluxo-do-pipeline" tabindex="-1">Fluxo do Pipeline <a class="header-anchor" href="#fluxo-do-pipeline" aria-label="Permalink to &quot;Fluxo do Pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Upload Imagem</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>[Validacao] formato, tamanho, plano</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>[Registro] pHash + dHash + aHash → ContentHash</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>[Celery Task] run_image_search</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    ├── Lens: SerpAPI (Google+Yandex+Baidu) ── paralelo</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    ├── pHash Enrichment (download thumbnails, compare)</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    ├── PIB Check (batch query por dominio)</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    ├── FaceIndex Search (InsightFace → Milvus)</span></span>
<span class="line"><span>    |</span></span>
<span class="line"><span>    └── Save Results + Alerts</span></span>
<span class="line"><span>         |</span></span>
<span class="line"><span>         v</span></span>
<span class="line"><span>    [Completo] Frontend poll /progress</span></span></code></pre></div><h2 id="progress-steps" tabindex="-1">Progress Steps <a class="header-anchor" href="#progress-steps" aria-label="Permalink to &quot;Progress Steps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Step</th><th>Descricao</th><th>Percentual</th></tr></thead><tbody><tr><td>1</td><td>Lendo imagem</td><td>10%</td></tr><tr><td>2</td><td>Buscando nos motores de busca</td><td>30%</td></tr><tr><td>3</td><td>Comparando impressoes digitais</td><td>50%</td></tr><tr><td>4</td><td>Verificando banco de pirataria</td><td>60%</td></tr><tr><td>5</td><td>Buscando por reconhecimento facial</td><td>70%</td></tr><tr><td>6</td><td>Finalizando resultados</td><td>90%</td></tr></tbody></table><h2 id="tipos-de-resultado" tabindex="-1">Tipos de Resultado <a class="header-anchor" href="#tipos-de-resultado" aria-label="Permalink to &quot;Tipos de Resultado&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Label no Frontend</th><th>Cor</th><th>Descricao</th></tr></thead><tbody><tr><td><code>serpapi</code></td><td>Motor de busca</td><td>Verde</td><td>Google Lens, Yandex, Baidu</td></tr><tr><td><code>social_reverse</code></td><td>Rede social</td><td>Ciano</td><td>API Social Reverse</td></tr><tr><td><code>face_match</code></td><td>Reconhecimento facial</td><td>Indigo</td><td>KubexFaceIndex (Milvus)</td></tr></tbody></table><h2 id="pib-badge" tabindex="-1">PIB Badge <a class="header-anchor" href="#pib-badge" aria-label="Permalink to &quot;PIB Badge&quot;">​</a></h2><p>Resultados de dominios com registros no PIB (PiracyIntelligence) exibem badge vermelho:</p><ul><li>&quot;3 registros no PIB&quot; → dominio tem CPF/CNPJ/PIX/crypto extraidos</li><li>Score recebe boost de +0.05 para dominios PIB-conhecidos</li></ul><h2 id="alertas-automaticos" tabindex="-1">Alertas Automaticos <a class="header-anchor" href="#alertas-automaticos" aria-label="Permalink to &quot;Alertas Automaticos&quot;">​</a></h2><p>Face matches com score &gt;= 0.70 geram Alert automatico:</p><ul><li><code>alert_type = &quot;face_match&quot;</code></li><li><code>detected_via = &quot;kubex_face_index&quot;</code></li><li>Visivel no painel de alertas do usuario</li></ul><h2 id="configuracao" tabindex="-1">Configuracao <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuracao&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variavel</th><th>Padrao</th><th>Descricao</th></tr></thead><tbody><tr><td><code>SERPAPI_KEY</code></td><td>-</td><td>Chave SerpAPI (obrigatoria)</td></tr><tr><td><code>FACE_INDEX_ENABLED</code></td><td><code>true</code></td><td>Ativa busca facial no pipeline</td></tr><tr><td><code>PIB_ENRICHMENT_ENABLED</code></td><td><code>true</code></td><td>Ativa enriquecimento PIB</td></tr><tr><td><code>FACE_SEARCH_THRESHOLD</code></td><td><code>0.60</code></td><td>Threshold minimo de similaridade facial</td></tr></tbody></table><h2 id="lgpd" tabindex="-1">LGPD <a class="header-anchor" href="#lgpd" aria-label="Permalink to &quot;LGPD&quot;">​</a></h2><ul><li>Imagem do upload: descartada apos processamento (<code>del img_bytes</code>)</li><li>Face embedding: gerado on-the-fly, NAO persistido (diferente do /face-search/web/unified que salva)</li><li>Thumbnails baixados: descartados apos comparacao pHash</li><li>Resultados: salvos como SearchResult (URL, score, dominio — sem imagem)</li></ul>`,28)])])}const m=e(i,[["render",n]]);export{h as __pageData,m as default};
